/**
 * MoneyWithdrawnHandler - Handle MoneyWithdrawn events
 *
 * Updates existing account state by decrementing balance
 */

import { EventHandler, type IEventHandler } from 'ceves';
import type { AccountState, MoneyWithdrawnEvent } from '../types';
import { MoneyWithdrawnEventSchema } from '../types';

@EventHandler({
  eventType: 'MoneyWithdrawn',
  aggregateType: 'account'
})
export class MoneyWithdrawnHandler
  implements IEventHandler<AccountState, MoneyWithdrawnEvent>
{
  eventType = 'MoneyWithdrawn';
  schema = MoneyWithdrawnEventSchema;

  /**
   * Apply MoneyWithdrawn event to decrement balance
   *
   * @param state - Current account state (must exist)
   * @param event - MoneyWithdrawn event with amount
   * @returns Updated AccountState with decreased balance
   */
  apply(
    state: AccountState | null,
    event: MoneyWithdrawnEvent
  ): AccountState {
    // MoneyWithdrawn requires existing state
    if (state === null) {
      throw new Error('MoneyWithdrawn event requires existing account state');
    }

    // Return new state with updated balance (immutable transformation)
    return {
      ...state,
      balance: state.balance - event.data.amount,
      version: event.version,
      timestamp: event.timestamp,
    };
  }
}
