/**
 * CevesApp - Main application class for Cloudflare Workers event sourcing
 *
 * This class orchestrates the entire event sourcing infrastructure:
 * - Initializes storage (R2/D1) with dependency injection support
 * - Auto-discovers and registers decorated command handlers
 * - Provides Workers-compatible fetch() handler
 * - Integrates all components from Epics 1-4
 *
 * @packageDocumentation
 */

import { Hono } from 'hono';
import type { R2Bucket, D1Database } from '@cloudflare/workers-types';
import type { IEventStore, ISnapshotStore } from '../storage/interfaces';
import { R2EventStore } from '../storage/R2EventStore';
import { R2SnapshotStore } from '../storage/R2SnapshotStore';
import { getCommandHandlers } from '../decorators/CommandHandler';
import { restoreState } from '../restoration/StateRestoration';
import type { BaseState } from '../schemas/State';
import type { ITenantResolver } from '../tenancy/TenantResolver';
import { ApiKeyTenantResolver } from '../tenancy/ApiKeyTenantResolver';

/**
 * Cloudflare environment bindings required by CevesApp
 *
 * @example
 * ```typescript
 * export interface Env extends CevesEnv {
 *   // Add your custom bindings here
 * }
 * ```
 */
export interface CevesEnv {
  /**
   * R2 bucket for event storage (required)
   *
   * Configure in wrangler.toml:
   * ```toml
   * [[r2_buckets]]
   * binding = "EVENTS_BUCKET"
   * bucket_name = "my-events"
   * ```
   */
  EVENTS_BUCKET: R2Bucket;

  /**
   * D1 database for snapshot storage (optional)
   *
   * If not provided, R2SnapshotStore will be used (default)
   *
   * Configure in wrangler.toml:
   * ```toml
   * [[d1_databases]]
   * binding = "SNAPSHOTS_DB"
   * database_name = "my-snapshots"
   * database_id = "..."
   * ```
   */
  SNAPSHOTS_DB?: D1Database;

  /**
   * D1 database for tenant/API key data (required for multitenancy)
   *
   * Used by ApiKeyTenantResolver to map API keys to organization IDs.
   *
   * Configure in wrangler.toml:
   * ```toml
   * [[d1_databases]]
   * binding = "TENANT_DB"
   * database_name = "ceves-tenants"
   * database_id = "..."
   * ```
   */
  TENANT_DB: D1Database;

  /**
   * Default organization ID for development/testing (optional)
   *
   * If set, requests without X-API-Key header will use this org ID.
   * If not set, missing API key will result in 401 error.
   *
   * **Security:** Only use in development - never set in production.
   *
   * @example
   * ```toml
   * [vars]
   * DEFAULT_ORG_ID = "default-org"
   * ```
   */
  DEFAULT_ORG_ID?: string;

  /**
   * Log level for Pino logger (optional)
   *
   * Values: 'silent', 'error', 'warn', 'info', 'debug', 'trace'
   * Default: 'info'
   */
  LOG_LEVEL?: string;
}

/**
 * Snapshot policy configuration for an aggregate type
 *
 * Controls when snapshots are automatically created after command execution
 *
 * @example
 * ```typescript
 * // Snapshot every 10 events
 * { interval: 10 }
 *
 * // Disable snapshots for this aggregate
 * { disabled: true }
 * ```
 */
export interface SnapshotPolicy {
  /**
   * Create snapshot every N events (must be positive integer)
   *
   * Example: interval=10 creates snapshots at versions 10, 20, 30, etc.
   */
  interval?: number;

  /**
   * Disable automatic snapshot creation for this aggregate
   *
   * Useful for:
   * - Append-only logs that are never queried
   * - Aggregates with very few events
   * - Testing scenarios
   */
  disabled?: boolean;
}

/**
 * Optional configuration for CevesApp
 *
 * Enables dependency injection for testing or custom storage implementations
 */
export interface CevesOptions {
  /**
   * Override default R2EventStore
   *
   * Useful for:
   * - Testing with in-memory store
   * - Custom event storage implementation
   *
   * @example
   * ```typescript
   * const app = new CevesApp(env, {
   *   eventStore: new InMemoryEventStore()
   * });
   * ```
   */
  eventStore?: IEventStore;

  /**
   * Override default R2SnapshotStore
   *
   * Useful for:
   * - Testing with in-memory store
   * - Using D1SnapshotStore instead of R2
   *
   * @example
   * ```typescript
   * const app = new CevesApp(env, {
   *   snapshotStore: new D1SnapshotStore(env.SNAPSHOTS_DB)
   * });
   * ```
   */
  snapshotStore?: ISnapshotStore;

  /**
   * Override default ApiKeyTenantResolver
   *
   * Useful for:
   * - Testing with mock resolver
   * - Using JWT resolver for B2C authentication
   * - Custom tenant resolution logic
   *
   * @example
   * ```typescript
   * const app = new CevesApp(env, {
   *   tenantResolver: new JwtTenantResolver(env.JWT_SECRET)
   * });
   * ```
   */
  tenantResolver?: ITenantResolver;

  /**
   * Per-aggregate snapshot policies
   *
   * Override default snapshot interval for specific aggregate types
   *
   * @example
   * ```typescript
   * new CevesApp(env, {
   *   snapshotPolicies: {
   *     'account': { interval: 10 },      // High-activity: snapshot every 10 events
   *     'order': { interval: 50 },        // Medium-activity: snapshot every 50 events
   *     'audit-log': { disabled: true }   // Never snapshot append-only logs
   *   }
   * });
   * ```
   */
  snapshotPolicies?: Record<string, SnapshotPolicy>;

  /**
   * Default snapshot interval for all aggregates (default: 10)
   *
   * Applies to all aggregate types unless overridden in snapshotPolicies
   *
   * @example
   * ```typescript
   * new CevesApp(env, {
   *   defaultSnapshotInterval: 100  // Snapshot every 100 events by default
   * });
   * ```
   */
  defaultSnapshotInterval?: number;
}

/**
 * Main application class for Ceves event sourcing
 *
 * Orchestrates all event sourcing infrastructure:
 * - Storage initialization (R2/D1)
 * - Command handler auto-registration
 * - HTTP request handling via Hono
 * - State restoration before command execution
 * - Event persistence after command execution
 *
 * @example
 * Basic usage:
 * ```typescript
 * export default {
 *   async fetch(request: Request, env: Env): Promise<Response> {
 *     const app = new CevesApp(env);
 *     return app.fetch(request);
 *   }
 * };
 * ```
 *
 * @example
 * With dependency injection (testing):
 * ```typescript
 * const app = new CevesApp(env, {
 *   eventStore: new InMemoryEventStore(),
 *   snapshotStore: new InMemorySnapshotStore()
 * });
 * ```
 */
export class CevesApp {
  /**
   * Hono application instance for HTTP routing
   * @internal
   */
  private app: Hono;

  /**
   * Event store instance (R2 or custom)
   * @internal
   */
  private eventStore: IEventStore;

  /**
   * Snapshot store instance (R2, D1, or custom)
   * @internal
   */
  private snapshotStore: ISnapshotStore;

  /**
   * Tenant resolver instance (API key, JWT, or custom)
   * @internal
   */
  private tenantResolver: ITenantResolver;

  /**
   * Per-aggregate snapshot policies
   * @internal
   */
  private snapshotPolicies: Record<string, SnapshotPolicy>;

  /**
   * Default snapshot interval (default: 10 events)
   * @internal
   */
  private defaultSnapshotInterval: number;

  /**
   * Create a new CevesApp instance
   *
   * @param env - Cloudflare environment bindings
   * @param options - Optional configuration for testing/customization
   *
   * @example
   * Production:
   * ```typescript
   * const app = new CevesApp(env);
   * ```
   *
   * @example
   * Testing:
   * ```typescript
   * const app = new CevesApp(mockEnv, {
   *   eventStore: new InMemoryEventStore(),
   *   snapshotStore: new InMemorySnapshotStore()
   * });
   * ```
   */
  constructor(env: CevesEnv, options?: CevesOptions) {
    // Initialize storage with dependency injection pattern
    // Default: R2EventStore + R2SnapshotStore using EVENTS_BUCKET
    // Override: Use provided stores for testing or custom implementations
    this.eventStore =
      options?.eventStore ?? new R2EventStore(env.EVENTS_BUCKET);
    this.snapshotStore =
      options?.snapshotStore ?? new R2SnapshotStore(env.EVENTS_BUCKET);

    // Initialize tenant resolver (Epic 8: Multitenancy)
    // Default: ApiKeyTenantResolver using TENANT_DB
    // Override: Use provided resolver for testing or custom auth (JWT, etc.)
    this.tenantResolver =
      options?.tenantResolver ??
      new ApiKeyTenantResolver(env.TENANT_DB, env.DEFAULT_ORG_ID);

    // Initialize snapshot configuration (Epic 8)
    // Default: snapshot every 10 events for all aggregates
    // Override: per-aggregate policies for fine-tuned control
    this.snapshotPolicies = options?.snapshotPolicies ?? {};
    this.defaultSnapshotInterval = options?.defaultSnapshotInterval ?? 10;

    // Validate snapshot configuration
    if (this.defaultSnapshotInterval <= 0) {
      throw new Error(
        `Invalid defaultSnapshotInterval: ${this.defaultSnapshotInterval}. Must be positive integer.`
      );
    }
    for (const [aggregateType, policy] of Object.entries(
      this.snapshotPolicies
    )) {
      if (policy.interval !== undefined && policy.interval <= 0) {
        throw new Error(
          `Invalid snapshot interval for '${aggregateType}': ${policy.interval}. Must be positive integer.`
        );
      }
    }

    // Initialize Hono application
    this.app = new Hono();

    // Auto-register all decorated command handlers
    // Implementation in Story 5.2
    this.registerCommandHandlers();
  }

  /**
   * Workers-compatible fetch handler
   *
   * Delegates HTTP request handling to Hono
   *
   * @param request - Incoming HTTP request
   * @returns HTTP response
   *
   * @example
   * ```typescript
   * export default {
   *   async fetch(request: Request, env: Env): Promise<Response> {
   *     const app = new CevesApp(env);
   *     return app.fetch(request);
   *   }
   * };
   * ```
   */
  async fetch(request: Request): Promise<Response> {
    return this.app.fetch(request);
  }

  /**
   * Get Hono app instance
   *
   * Exposed for OpenAPI integration with Chanfana.
   * Use this to wrap the app with fromHono() for automatic OpenAPI schema generation.
   *
   * @returns Hono app instance
   *
   * @example
   * ```typescript
   * import { fromHono } from 'chanfana';
   *
   * const cevesApp = new CevesApp(env);
   * const openapi = fromHono(cevesApp.getHonoApp(), {
   *   schema: {
   *     info: { title: 'My API', version: '1.0.0' }
   *   }
   * });
   * ```
   */
  getHonoApp(): Hono {
    return this.app;
  }

  /**
   * Get event store instance
   *
   * Exposed for testing and advanced use cases
   *
   * @internal
   */
  getEventStore(): IEventStore {
    return this.eventStore;
  }

  /**
   * Get snapshot store instance
   *
   * Exposed for testing and advanced use cases
   *
   * @internal
   */
  getSnapshotStore(): ISnapshotStore {
    return this.snapshotStore;
  }

  /**
   * Get snapshot policy for an aggregate type
   *
   * Returns the effective snapshot policy (per-aggregate override or default)
   *
   * @param aggregateType - Aggregate type (e.g., "account", "order")
   * @returns Snapshot policy with interval or disabled flag
   *
   * @internal
   *
   * @example
   * ```typescript
   * const policy = app.getSnapshotPolicy('account');
   * if (!policy.disabled && version % policy.interval === 0) {
   *   // Create snapshot
   * }
   * ```
   */
  getSnapshotPolicy(aggregateType: string): SnapshotPolicy {
    // Return per-aggregate policy if defined
    const aggregatePolicy = this.snapshotPolicies[aggregateType];
    if (aggregatePolicy) {
      return {
        interval: aggregatePolicy.interval ?? this.defaultSnapshotInterval,
        disabled: aggregatePolicy.disabled ?? false,
      };
    }

    // Return default policy
    return {
      interval: this.defaultSnapshotInterval,
      disabled: false,
    };
  }

  /**
   * Check if a snapshot should be created for this aggregate at this version
   *
   * Returns true if:
   * - Snapshots are not disabled for this aggregate
   * - Version is greater than 0
   * - Version is at snapshot interval boundary (version % interval === 0)
   *
   * @param aggregateType - Aggregate type (e.g., "account")
   * @param version - Current aggregate version after event persistence
   * @returns true if snapshot should be created
   *
   * @internal
   *
   * @example
   * ```typescript
   * // With interval = 10:
   * shouldCreateSnapshot('account', 9)   // false (not at boundary)
   * shouldCreateSnapshot('account', 10)  // true  (10 % 10 === 0)
   * shouldCreateSnapshot('account', 11)  // false (not at boundary)
   * shouldCreateSnapshot('account', 20)  // true  (20 % 10 === 0)
   * ```
   */
  shouldCreateSnapshot(aggregateType: string, version: number): boolean {
    // Get effective policy for this aggregate
    const policy = this.getSnapshotPolicy(aggregateType);

    // Don't create snapshots if disabled
    if (policy.disabled) {
      return false;
    }

    // Never snapshot version 0 (no events yet)
    if (version <= 0) {
      return false;
    }

    // Create snapshot at interval boundaries
    return version % policy.interval! === 0;
  }

  /**
   * Calculate current state for an aggregate
   *
   * Loads all events and snapshots, then replays them to compute current state.
   * This is the same process used during command execution, ensuring accuracy.
   *
   * @param aggregateType - Aggregate type (e.g., "account")
   * @param aggregateId - Aggregate ID (e.g., "acc-123")
   * @returns Current aggregate state, or null if aggregate doesn't exist
   *
   * @internal
   *
   * @example
   * ```typescript
   * const state = await app.calculateCurrentState('account', 'acc-123');
   * if (state) {
   *   console.log(`Account balance: ${state.balance}`);
   * }
   * ```
   */
  async calculateCurrentState(
    aggregateType: string,
    aggregateId: string
  ): Promise<BaseState | null> {
    // Use existing state restoration logic (loads snapshots + events)
    // This ensures snapshot accuracy matches runtime state
    return await restoreState(
      aggregateType,
      aggregateId,
      this.eventStore,
      this.snapshotStore
    );
  }

  /**
   * Maybe create snapshot for an aggregate at current version
   *
   * This method is designed to be called from ExecutionContext.waitUntil()
   * for async background snapshot creation after command execution.
   *
   * Flow:
   * 1. Check if snapshot should be created (policy + version check)
   * 2. Calculate current state by replaying all events
   * 3. Save snapshot to storage
   * 4. Log any errors (never throws - safe for waitUntil)
   *
   * @param aggregateType - Aggregate type (e.g., "account")
   * @param aggregateId - Aggregate ID (e.g., "acc-123")
   * @param version - Current version after event persistence
   *
   * @internal
   *
   * @example
   * ```typescript
   * // In CommandRoute.handle():
   * await this.eventStore.save(event);
   * c.executionCtx.waitUntil(
   *   app.maybeCreateSnapshot('account', 'acc-123', newVersion)
   * );
   * return c.json({ success: true });
   * ```
   */
  async maybeCreateSnapshot(
    aggregateType: string,
    aggregateId: string,
    version: number
  ): Promise<void> {
    try {
      // Check if snapshot should be created
      if (!this.shouldCreateSnapshot(aggregateType, version)) {
        return;
      }

      console.log(
        `Creating snapshot for ${aggregateType}/${aggregateId} at version ${version}`
      );

      // Calculate current state
      const state = await this.calculateCurrentState(aggregateType, aggregateId);

      // If aggregate doesn't exist, skip snapshot
      if (!state) {
        console.warn(
          `Cannot create snapshot for ${aggregateType}/${aggregateId}: aggregate not found`
        );
        return;
      }

      // Save snapshot
      await this.snapshotStore.save({
        aggregateType,
        aggregateId,
        version,
        timestamp: new Date().toISOString(),
        state,
      });

      console.log(
        `Snapshot created successfully for ${aggregateType}/${aggregateId} at version ${version}`
      );
    } catch (error) {
      // NEVER throw - this runs in waitUntil() and errors would terminate Worker
      console.error(
        `Snapshot creation failed for ${aggregateType}/${aggregateId} at version ${version}:`,
        error
      );
    }
  }

  /**
   * Register all decorated command handlers as Hono routes
   *
   * Automatically discovers handlers via decorator registry
   * and wires them to HTTP endpoints.
   *
   * Story 5.2: Auto-registration implementation
   *
   * @internal
   */
  private registerCommandHandlers(): void {
    // Get all decorated command handlers from registry
    const handlers = getCommandHandlers();

    for (const [_name, HandlerClass] of handlers) {
      // Create instance of handler class
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const handler = new (HandlerClass as any)();

      // Check if handler has setStores method (from CommandRoute)
      if ('setStores' in handler && typeof handler.setStores === 'function') {
        // Inject storage dependencies, CevesApp reference, and tenant resolver
        handler.setStores(this.eventStore, this.snapshotStore, this, this.tenantResolver);
      }

      // Check if handler has route property
      if ('route' in handler && typeof handler.route === 'string') {
        // Register route with Hono
        // Default to POST for command handlers
        this.app.post(handler.route, async (c) => {
          // Delegate to handler's handle method
          if ('handle' in handler && typeof handler.handle === 'function') {
            return handler.handle(c);
          }
          // Fallback if no handle method
          return c.json({ error: 'Handler missing handle method' }, 500);
        });
      }
    }
  }
}
