/**
 * CommandRoute - Base class for command handlers
 *
 * Provides automatic state restoration before command execution and
 * automatic event persistence after successful execution.
 *
 * User command handlers extend this class and implement only the pure
 * domain logic in the execute() method.
 *
 * @packageDocumentation
 */

import { OpenAPIRoute } from 'chanfana';
import type { Context } from 'hono';
import type { IEventStore, ISnapshotStore } from '../storage/interfaces';
import { restoreState } from '../restoration/StateRestoration';
import type { BaseState } from '../schemas/State';
import { ZodError } from 'zod';
import {
  AggregateNotFoundError,
  EventApplicationError,
} from '../errors';
import {
  EventWriteError,
  SnapshotStoreError,
  SnapshotCorruptedError,
} from '../storage/errors';
import type { ITenantResolver } from '../tenancy/TenantResolver';
import {
  MissingApiKeyError,
  InvalidApiKeyError,
  UnauthorizedAccessError,
} from '../tenancy/errors';

/**
 * Base class for command handlers
 *
 * Handles infrastructure concerns automatically:
 * - State restoration before command execution
 * - Event persistence after successful execution
 * - HTTP response formatting
 * - Error handling (Story 5.4)
 *
 * Users extend this class and implement only the execute() method with pure domain logic.
 *
 * @example
 * ```typescript
 * @CommandHandler
 * export class CreateAccountHandler extends CommandRoute {
 *   route = '/accounts/:id/create';
 *
 *   async execute(command: CreateAccountCommand, state: AccountState | null) {
 *     if (state !== null) {
 *       throw new Error('Account already exists');
 *     }
 *
 *     return {
 *       type: 'AccountCreated',
 *       data: { email: command.email, name: command.name }
 *     };
 *   }
 * }
 * ```
 */
export abstract class CommandRoute extends OpenAPIRoute {
  /**
   * Event store instance (injected by CevesApp)
   * @internal
   */
  protected eventStore!: IEventStore;

  /**
   * Snapshot store instance (injected by CevesApp)
   * @internal
   */
  protected snapshotStore!: ISnapshotStore;

  /**
   * CevesApp instance for snapshot creation (injected by CevesApp)
   * @internal
   */
  protected cevesApp!: any; // Using 'any' to avoid circular dependency

  /**
   * Tenant resolver instance (injected by CevesApp)
   * @internal
   */
  protected tenantResolver!: ITenantResolver;

  /**
   * Optional state provider for Durable Object mode
   * When set, provides in-memory state instead of restoring from storage
   * @internal
   */
  protected stateProvider?: () => Promise<BaseState | null>;

  /**
   * User-defined command handler logic
   *
   * Implement this method with pure domain logic. Receives:
   * - command: Validated command payload
   * - state: Current aggregate state (null if not exists)
   *
   * Returns event to be persisted.
   *
   * @param command - Validated command payload
   * @param state - Current aggregate state (null for new aggregates)
   * @returns Event object with type and data
   *
   * @example
   * ```typescript
   * async executeCommand(command: CreateAccountCommand, state: AccountState | null) {
   *   if (state !== null) {
   *     throw new Error('Account already exists');
   *   }
   *
   *   return {
   *     type: 'AccountCreated',
   *     data: { email: command.email, name: command.name }
   *   };
   * }
   * ```
   */
  abstract executeCommand(command: unknown, state: unknown): Promise<{
    type: string;
    data: unknown;
  }>;

  /**
   * Set storage instances, tenant resolver, and CevesApp reference (called by CevesApp)
   *
   * @internal
   */
  setStores(
    eventStore: IEventStore,
    snapshotStore: ISnapshotStore,
    cevesApp: any,
    tenantResolver: ITenantResolver
  ): void {
    this.eventStore = eventStore;
    this.snapshotStore = snapshotStore;
    this.cevesApp = cevesApp;
    this.tenantResolver = tenantResolver;
  }

  /**
   * Set state provider for Durable Object mode
   *
   * In DO mode, state is already in memory, so the provider simply
   * returns the current state without restoring from storage.
   *
   * @param provider - Function that returns current aggregate state
   * @internal
   */
  setStateProvider(provider: () => Promise<BaseState | null>): void {
    this.stateProvider = provider;
  }

  /**
   * Handle command in Durable Object mode
   *
   * This method is called by AggregateObject when executing commands.
   * Unlike handle(), it doesn't persist the event - the DO will handle that.
   * It returns the event and version instead of a Response.
   *
   * Flow:
   * 1. Get state from state provider (in-memory, fast!)
   * 2. Resolve tenant from request
   * 3. Enforce tenant access control
   * 4. Execute domain logic to get event
   * 5. Set orgId for new aggregates
   * 6. Return event + version (DO will apply and persist)
   *
   * @param request - HTTP request
   * @param command - Parsed command payload
   * @returns Event and version number
   * @internal
   */
  async handleDO(request: Request, command: any): Promise<{ event: any; version: number }> {
    // Get in-memory state from provider (fast!)
    const state = this.stateProvider ? await this.stateProvider() : null;

    // Resolve tenant from request
    const requestOrgId = await this.tenantResolver.resolveOrgId(request);

    // Enforce tenant access control
    await this.enforceTenantAccess(requestOrgId, state);

    // Execute domain logic
    const event = await this.executeCommand(command, state);

    // Set orgId for new aggregates
    if (state === null) {
      event.data = {
        ...(event.data as Record<string, unknown>),
        orgId: requestOrgId,
      };
    } else {
      // For existing aggregates, ensure orgId consistency
      event.data = {
        ...(event.data as Record<string, unknown>),
        orgId: state.orgId,
      };
    }

    // Calculate version
    const version = (state?.version ?? 0) + 1;

    return { event, version };
  }

  /**
   * Resolve organization ID from request (via API key or other auth method)
   *
   * @param c - Hono context containing the request
   * @returns Organization ID for the requesting tenant
   * @throws MissingApiKeyError if API key is missing and no default org
   * @throws InvalidApiKeyError if API key is invalid or revoked
   *
   * @internal
   */
  protected async resolveTenantFromRequest(c: Context): Promise<string> {
    return await this.tenantResolver.resolveOrgId(c.req.raw);
  }

  /**
   * Enforce tenant access control - verify request orgId matches state orgId
   *
   * For existing aggregates: validates that the requesting tenant owns the aggregate
   * For new aggregates: no check needed (orgId will be set on first event)
   *
   * @param requestOrgId - Organization ID from the request (resolved from API key)
   * @param state - Current aggregate state (null for new aggregates)
   * @throws UnauthorizedAccessError if tenant doesn't own this aggregate
   *
   * @internal
   */
  protected async enforceTenantAccess(
    requestOrgId: string,
    state: BaseState | null
  ): Promise<void> {
    // New aggregates (state === null) are allowed - orgId will be set on creation
    if (state === null) {
      return;
    }

    // Existing aggregates must belong to the requesting tenant
    if (state.orgId !== requestOrgId) {
      throw new UnauthorizedAccessError(
        `Access denied: aggregate belongs to different organization`
      );
    }
  }

  /**
   * Handle HTTP request with automatic state restoration and event persistence
   *
   * Orchestrates the complete command processing flow:
   * 1. Resolve orgId from request (via tenant resolver)
   * 2. Extract and validate command from request (via Chanfana)
   * 3. Restore current aggregate state from events + snapshots
   * 4. Enforce tenant access control (verify orgId matches)
   * 5. Execute user's domain logic (execute method)
   * 6. Set orgId for new aggregates (if state was null)
   * 7. Persist returned event with auto-incremented version
   * 8. Return success response
   *
   * Error handling added in Story 5.4
   * Tenant enforcement added in Epic 7
   *
   * @param c - Hono context
   * @returns HTTP response
   *
   * @internal
   */
  async handle(c: Context): Promise<Response> {
    try {
      // Step 1: Resolve orgId from request (via API key or JWT)
      const requestOrgId = await this.resolveTenantFromRequest(c);

      // Step 2: Get and validate request data via Chanfana
      // This validates against the Zod schema defined in @CommandHandler decorator
      const validatedData = await this.getValidatedData();
      const params = validatedData.params ?? {};
      const command = validatedData.body ?? {};
      const aggregateType = command.aggregateType ?? 'unknown';
      const aggregateId = command.aggregateId ?? params.id ?? 'unknown';

      // Step 3: Restore state
      const state = await restoreState<BaseState>(
        aggregateType,
        aggregateId,
        this.eventStore,
        this.snapshotStore
      );

      // Step 4: Enforce tenant access control
      await this.enforceTenantAccess(requestOrgId, state);

      // Step 5: Execute user's command logic
      const event = await this.executeCommand(command, state);

      // Step 6: Set orgId for new aggregates (state was null)
      // Ensure event data has orgId field
      if (state === null) {
        // For new aggregates, inject orgId from request
        event.data = {
          ...(event.data as Record<string, unknown>),
          orgId: requestOrgId,
        };
      } else {
        // For existing aggregates, ensure orgId consistency
        event.data = {
          ...(event.data as Record<string, unknown>),
          orgId: state.orgId,
        };
      }

      // Step 7: Persist event
      const newVersion = (state?.version ?? 0) + 1;
      await this.eventStore.save({
        aggregateType,
        aggregateId,
        version: newVersion,
        type: event.type,
        timestamp: new Date().toISOString(),
        data: event.data,
      });

      // Step 7.5: Maybe create snapshot (Epic 8)
      // Schedule snapshot creation in background (non-blocking)
      // Only if ExecutionContext is available (testing may not have it)
      if (c.executionCtx && this.cevesApp) {
        c.executionCtx.waitUntil(
          this.cevesApp.maybeCreateSnapshot(aggregateType, aggregateId, newVersion)
        );
      }

      // Step 8: Return success response
      return c.json({
        success: true,
        aggregateId,
        version: newVersion,
      });
    } catch (error) {
      // Story 5.4: Comprehensive error handling with HTTP status code mapping
      // Epic 7: Tenant-specific error handling

      // Tenant authentication errors → 401 Unauthorized
      if (error instanceof MissingApiKeyError || error instanceof InvalidApiKeyError) {
        return c.json(
          {
            success: false,
            error: 'Authentication failed',
            message: error.message,
          },
          401
        );
      }

      // Tenant authorization errors → 403 Forbidden
      if (error instanceof UnauthorizedAccessError) {
        return c.json(
          {
            success: false,
            error: 'Access denied',
            message: error.message,
          },
          403
        );
      }

      // Zod validation errors → 400 Bad Request
      if (error instanceof ZodError) {
        return c.json(
          {
            success: false,
            error: 'Validation failed',
            details: error.errors,
          },
          400
        );
      }

      // Aggregate not found → 404 Not Found
      if (error instanceof AggregateNotFoundError) {
        return c.json(
          {
            success: false,
            error: 'Aggregate not found',
            aggregateType: error.aggregateType,
            aggregateId: error.aggregateId,
          },
          404
        );
      }

      // Event write errors → 500 Internal Server Error
      if (error instanceof EventWriteError) {
        return c.json(
          {
            success: false,
            error: 'Failed to persist event',
            message: error.message,
          },
          500
        );
      }

      // Snapshot store errors → 500
      if (
        error instanceof SnapshotStoreError ||
        error instanceof SnapshotCorruptedError
      ) {
        return c.json(
          {
            success: false,
            error: 'Snapshot operation failed',
            message: error.message,
          },
          500
        );
      }

      // Event application errors → 500 (indicates missing handler registration)
      if (error instanceof EventApplicationError) {
        return c.json(
          {
            success: false,
            error: 'Event application failed',
            message: error.message,
          },
          500
        );
      }

      // Domain errors (thrown by user's execute method) → 400
      // Any Error thrown by execute() is treated as a domain validation error
      if (error instanceof Error) {
        return c.json(
          {
            success: false,
            error: 'Domain error',
            message: error.message,
          },
          400
        );
      }

      // Unknown errors → 500
      return c.json(
        {
          success: false,
          error: 'Internal server error',
          message: 'Unknown error occurred',
        },
        500
      );
    }
  }
}
