/**
 * Event Handler Decorator & Registry for Ceves Event Sourcing Library
 *
 * Enhanced decorator supporting both legacy mode (stateless) and DO mode.
 * Event handlers transform aggregate state based on events.
 *
 * @packageDocumentation
 */

import type { z } from 'zod';
import type { BaseState } from '../schemas/State';
import type { StoredEvent } from '../storage/interfaces';

/**
 * Metadata for event handler registration (DO mode)
 */
export interface EventHandlerMetadata {
  /** Event type this handler processes (e.g., 'AccountDebited') */
  eventType: string;

  /** Aggregate type this event belongs to (e.g., 'bank-account') */
  aggregateType: string;
}

/**
 * Event handler interface - all event handlers must implement this
 *
 * Event handlers are pure functions that transform state based on events.
 * They should have no side effects and always return a new state object.
 *
 * @template TState - Aggregate state type
 * @template TEvent - Event data type
 */
export interface IEventHandler<TState extends BaseState = any, TEvent = any> {
  /**
   * Apply event to current state, returning new state
   *
   * @param state - Current aggregate state (null for first event)
   * @param event - Event to apply
   * @returns New state after applying event
   */
  apply(state: TState | null, event: StoredEvent): TState;

  /**
   * Event type (for legacy mode compatibility)
   * @deprecated Use metadata-based decorator instead
   */
  eventType?: string;

  /**
   * Event schema (for legacy mode compatibility)
   * @deprecated Use metadata-based decorator instead
   */
  schema?: z.ZodSchema<TEvent>;
}

/**
 * Registry entry for event handlers (DO mode)
 */
export interface EventHandlerEntry {
  /** Handler class constructor */
  handlerClass: new () => IEventHandler<any, any>;

  /** Metadata for event identification */
  metadata: EventHandlerMetadata;
}

/**
 * Static registry for DO mode event handlers
 * Keyed by "${aggregateType}:${eventType}"
 */
const EVENT_HANDLERS = new Map<string, EventHandlerEntry>();

/**
 * Legacy registry for backward compatibility
 * Keyed by eventType only
 */
const LEGACY_EVENT_HANDLERS = new Map<string, IEventHandler>();

/**
 * Event Handler decorator - supports two modes:
 *
 * 1. **Legacy mode**: @EventHandler (no args) - handler has eventType property
 * 2. **DO mode**: @EventHandler(metadata) - with aggregateType + eventType
 *
 * @example Legacy mode:
 * ```typescript
 * @EventHandler
 * export class AccountCreatedHandler implements IEventHandler {
 *   eventType = 'AccountCreated';
 *   schema = AccountCreatedEventSchema;
 *
 *   apply(state, event) {
 *     return { id: event.aggregateId, balance: 0, version: event.version };
 *   }
 * }
 * ```
 *
 * @example DO mode:
 * ```typescript
 * @EventHandler({
 *   eventType: 'AccountDebited',
 *   aggregateType: 'bank-account'
 * })
 * export class AccountDebitedHandler implements IEventHandler<BankAccountState> {
 *   apply(state, event) {
 *     return { ...state, balance: state.balance - event.data.amount };
 *   }
 * }
 * ```
 */
export function EventHandler(
  metadataOrTarget: EventHandlerMetadata | Function,
  _context?: ClassDecoratorContext
): void | ((target: Function, context: ClassDecoratorContext) => void) {
  // Check if called with metadata (DO mode) or without (legacy mode)
  if (typeof metadataOrTarget === 'function') {
    // Legacy mode: @EventHandler (no args)
    const target = metadataOrTarget;

    // Create instance to access eventType property
    const instance = new (target as any)() as IEventHandler;

    // Register in legacy registry
    if (instance.eventType) {
      LEGACY_EVENT_HANDLERS.set(instance.eventType, instance);
    }

    return;
  }

  // DO mode: @EventHandler(metadata)
  const metadata = metadataOrTarget;

  // Return decorator function
  return function (target: Function, _context: ClassDecoratorContext): void {
    // Generate unique key for this event handler
    const key = `${metadata.aggregateType}:${metadata.eventType}`;

    // Register handler with metadata
    EVENT_HANDLERS.set(key, {
      handlerClass: target as new () => IEventHandler<any, any>,
      metadata
    });

    // Also register in legacy registry for backward compatibility
    const instance = new (target as any)() as IEventHandler;
    LEGACY_EVENT_HANDLERS.set(metadata.eventType, instance);
  };
}

/**
 * Get all event handlers registered with metadata (DO mode)
 *
 * @returns Map of event handlers with metadata
 */
export function getEventHandlers(): Map<string, EventHandlerEntry> {
  return EVENT_HANDLERS;
}

/**
 * Get legacy event handlers (stateless mode)
 *
 * @returns Map of eventType → handler instance
 */
export function getAllEventHandlers(): Map<string, IEventHandler> {
  return LEGACY_EVENT_HANDLERS;
}

/**
 * Get legacy event handler by event type
 *
 * @param eventType - Event type to find
 * @returns Handler instance or undefined
 */
export function getEventHandler(eventType: string): IEventHandler | undefined {
  return LEGACY_EVENT_HANDLERS.get(eventType);
}

/**
 * Get event handlers for specific aggregate type (DO mode)
 *
 * @param aggregateType - Aggregate type to filter by
 * @returns Array of event handler entries for that aggregate
 */
export function getHandlersByAggregateType(
  aggregateType: string
): EventHandlerEntry[] {
  const handlers: EventHandlerEntry[] = [];

  for (const [_key, entry] of EVENT_HANDLERS) {
    if (entry.metadata.aggregateType === aggregateType) {
      handlers.push(entry);
    }
  }

  return handlers;
}

/**
 * Find event handler by event type and aggregate type (DO mode)
 *
 * @param eventType - Event type to find handler for
 * @param aggregateType - Aggregate type
 * @returns Event handler entry or undefined
 */
export function findEventHandler(
  eventType: string,
  aggregateType: string
): EventHandlerEntry | undefined {
  const key = `${aggregateType}:${eventType}`;
  return EVENT_HANDLERS.get(key);
}

/**
 * Apply event to state using registered handler (DO mode)
 *
 * Convenience function that finds and applies the appropriate event handler.
 *
 * @param aggregateType - Aggregate type
 * @param state - Current state (null for first event)
 * @param event - Event to apply
 * @returns New state after applying event
 * @throws Error if no handler registered for event type
 */
export function applyEventToState<TState extends BaseState>(
  aggregateType: string,
  state: TState | null,
  event: StoredEvent
): TState {
  const handlerEntry = findEventHandler(event.type, aggregateType);

  if (!handlerEntry) {
    throw new Error(
      `No event handler registered for event type "${event.type}" on aggregate "${aggregateType}"`
    );
  }

  const handler = new handlerEntry.handlerClass();
  return handler.apply(state, event) as TState;
}

/**
 * Clear all registered event handlers
 * FOR TESTING ONLY
 */
export function clearEventHandlers(): void {
  EVENT_HANDLERS.clear();
  LEGACY_EVENT_HANDLERS.clear();
}
