/**
 * DepositHandler - Deposit money into an existing account
 *
 * Domain Rules:
 * - Account must exist (state must not be null)
 * - Deposit amount must be positive
 */

import { CommandHandler, BusinessRuleViolationError } from 'ceves';
import { OpenAPIRoute } from 'chanfana';
import { z } from 'zod';
import type { DepositCommand, AccountState } from '../types';

// Request/Response Schemas for Chanfana
const DepositParams = z.object({
  id: z.string().describe('Account ID'),
});

const DepositBody = z.object({
  amount: z.number().positive().describe('Deposit amount'),
});

const DepositResponse = z.object({
  success: z.boolean(),
  aggregateId: z.string(),
  version: z.number(),
});

@CommandHandler({
  route: '/accounts/:id/deposit',
  aggregateType: 'account',
  method: 'POST',
  schema: {
    request: {
      params: DepositParams,
      body: DepositBody,
    },
    responses: {
      200: DepositResponse,
      400: z.object({ error: z.string(), message: z.string() }),
    },
  },
  openapi: {
    summary: 'Deposit money into account',
    description: 'Adds money to an existing bank account',
    tags: ['Bank Account'],
  },
})
export class DepositHandler extends OpenAPIRoute {
  /**
   * Execute the Deposit command
   *
   * @param command - Validated Deposit command with amount
   * @param state - Current account state (must exist)
   * @returns MoneyDeposited event
   * @throws Error if account does not exist
   */
  async executeCommand(
    command: DepositCommand,
    state: AccountState | null
  ): Promise<{ type: string; data: unknown }> {
    // Business rule: Cannot deposit to non-existent account
    if (state === null) {
      throw new BusinessRuleViolationError('Account not found');
    }

    // Return event to be persisted
    return {
      type: 'MoneyDeposited',
      data: {
        amount: command.amount,
      },
    };
  }
}
