/**
 * MoneyDepositedHandler - Handle MoneyDeposited events
 *
 * Updates existing account state by incrementing balance
 */

import { EventHandler, type IEventHandler } from 'ceves';
import type { AccountState, MoneyDepositedEvent } from '../types';
import { MoneyDepositedEventSchema } from '../types';

@EventHandler({
  eventType: 'MoneyDeposited',
  aggregateType: 'account'
})
export class MoneyDepositedHandler
  implements IEventHandler<AccountState, MoneyDepositedEvent>
{
  eventType = 'MoneyDeposited';
  schema = MoneyDepositedEventSchema;

  /**
   * Apply MoneyDeposited event to increment balance
   *
   * @param state - Current account state (must exist)
   * @param event - MoneyDeposited event with amount
   * @returns Updated AccountState with increased balance
   */
  apply(
    state: AccountState | null,
    event: MoneyDepositedEvent
  ): AccountState {
    // MoneyDeposited requires existing state
    if (state === null) {
      throw new Error('MoneyDeposited event requires existing account state');
    }

    // Return new state with updated balance (immutable transformation)
    return {
      ...state,
      balance: state.balance + event.data.amount,
      version: event.version,
      timestamp: event.timestamp,
    };
  }
}
