/**
 * WithdrawHandler - Withdraw money from an existing account
 *
 * Domain Rules:
 * - Account must exist (state must not be null)
 * - Withdrawal amount must be positive
 * - Account must have sufficient balance
 */

import { CommandHandler, BusinessRuleViolationError } from 'ceves';
import { OpenAPIRoute } from 'chanfana';
import { z } from 'zod';
import type { WithdrawCommand, AccountState } from '../types';

// Request/Response Schemas for Chanfana
const WithdrawParams = z.object({
  id: z.string().describe('Account ID'),
});

const WithdrawBody = z.object({
  amount: z.number().positive().describe('Withdrawal amount'),
});

const WithdrawResponse = z.object({
  success: z.boolean(),
  aggregateId: z.string(),
  version: z.number(),
});

@CommandHandler({
  route: '/accounts/:id/withdraw',
  aggregateType: 'account',
  method: 'POST',
  schema: {
    request: {
      params: WithdrawParams,
      body: WithdrawBody,
    },
    responses: {
      200: WithdrawResponse,
      400: z.object({ error: z.string(), message: z.string() }),
    },
  },
  openapi: {
    summary: 'Withdraw money from account',
    description: 'Withdraws money from an existing bank account',
    tags: ['Bank Account'],
  },
})
export class WithdrawHandler extends OpenAPIRoute {
  /**
   * Execute the Withdraw command
   *
   * @param command - Validated Withdraw command with amount
   * @param state - Current account state (must exist with sufficient balance)
   * @returns MoneyWithdrawn event
   * @throws Error if account does not exist or has insufficient funds
   */
  async executeCommand(
    command: WithdrawCommand,
    state: AccountState | null
  ): Promise<{ type: string; data: unknown }> {
    // Business rule: Cannot withdraw from non-existent account
    if (state === null) {
      throw new BusinessRuleViolationError('Account not found');
    }

    // Business rule: Cannot withdraw more than current balance
    if (state.balance < command.amount) {
      throw new BusinessRuleViolationError(
        `Insufficient funds. Current balance: ${state.balance}, requested: ${command.amount}`
      );
    }

    // Return event to be persisted
    return {
      type: 'MoneyWithdrawn',
      data: {
        amount: command.amount,
      },
    };
  }
}
