/**
 * Command Handler Decorator & Registry for Ceves Event Sourcing Library
 *
 * Enhanced decorator with Chanfana/OpenAPI integration for Durable Objects mode.
 * Supports both stateless mode (original) and DO mode (new) with metadata.
 *
 * @packageDocumentation
 */

import type { z } from 'zod';
import type { OpenAPIRoute } from 'chanfana';

/**
 * Metadata for command handler registration
 * Used in Durable Objects mode for auto-endpoint generation
 */
export interface CommandHandlerMetadata {
  /** HTTP route pattern (e.g., '/accounts/:id/debit') */
  route: string;

  /** Aggregate type this command operates on (e.g., 'bank-account') */
  aggregateType: string;

  /** HTTP method (default: POST) */
  method?: 'POST' | 'PUT' | 'DELETE' | 'GET' | 'PATCH';

  /** Chanfana/OpenAPI request and response schemas */
  schema: {
    request?: {
      params?: z.ZodSchema;
      query?: z.ZodSchema;
      body?: z.ZodSchema;
      headers?: z.ZodSchema;
    };
    responses?: {
      [statusCode: number]: z.ZodSchema;
    };
  };

  /** OpenAPI documentation metadata */
  openapi?: {
    summary?: string;
    description?: string;
    tags?: string[];
    deprecated?: boolean;
    operationId?: string;
  };
}

/**
 * Registry entry for command handlers
 */
export interface CommandHandlerEntry {
  /** Handler class (extends OpenAPIRoute for Chanfana integration) */
  handlerClass: typeof OpenAPIRoute;

  /** Metadata for routing and documentation */
  metadata: CommandHandlerMetadata;
}

/**
 * Static registry storing all command handler classes with metadata.
 * Keyed by "${aggregateType}:${route}" for unique identification.
 */
const COMMAND_HANDLERS = new Map<string, CommandHandlerEntry>();

/**
 * Simple registry for backward compatibility (stateless mode)
 * Maps class name → constructor
 */
const LEGACY_COMMAND_HANDLERS = new Map<string, Function>();

/**
 * Command Handler decorator - supports two modes:
 *
 * 1. **Legacy mode** (backward compatible): @CommandHandler with no args
 * 2. **DO mode** (new): @CommandHandler(metadata) with route, schema, etc.
 *
 * @example Legacy mode (stateless):
 * ```typescript
 * @CommandHandler
 * class CreateAccountHandler extends CommandRoute {
 *   async executeCommand(cmd, state) { ... }
 * }
 * ```
 *
 * @example DO mode (with metadata):
 * ```typescript
 * @CommandHandler({
 *   route: '/accounts/:id/create',
 *   aggregateType: 'bank-account',
 *   schema: {
 *     request: {
 *       params: z.object({ id: z.string() }),
 *       body: CreateAccountSchema
 *     },
 *     responses: {
 *       201: CreateAccountResponseSchema
 *     }
 *   },
 *   openapi: {
 *     summary: 'Create bank account',
 *     tags: ['Bank Account']
 *   }
 * })
 * class CreateAccountHandler extends OpenAPIRoute {
 *   async executeCommand(cmd, state) { ... }
 * }
 * ```
 */
export function CommandHandler(
  metadataOrTarget: CommandHandlerMetadata | Function,
  _context?: ClassDecoratorContext
): void | ((target: Function, context: ClassDecoratorContext) => void) {
  // Check if called with metadata (DO mode) or without (legacy mode)
  if (typeof metadataOrTarget === 'function') {
    // Legacy mode: @CommandHandler (no args)
    const target = metadataOrTarget;
    const className = target.name;
    LEGACY_COMMAND_HANDLERS.set(className, target);
    return;
  }

  // DO mode: @CommandHandler(metadata)
  const metadata = metadataOrTarget;

  // Return decorator function
  return function (target: Function, _context: ClassDecoratorContext): void {
    // Generate unique key for this handler
    const key = `${metadata.aggregateType}:${metadata.route}`;

    // Register handler with metadata
    COMMAND_HANDLERS.set(key, {
      handlerClass: target as typeof OpenAPIRoute,
      metadata
    });

    // Also add to legacy registry for backward compatibility
    LEGACY_COMMAND_HANDLERS.set(target.name, target);
  };
}

/**
 * Get all command handlers registered with metadata (DO mode)
 *
 * @returns Map of handlers with full metadata
 *
 * @example
 * ```typescript
 * const handlers = getCommandHandlers();
 *
 * for (const [key, { handlerClass, metadata }] of handlers) {
 *   console.log(`Route: ${metadata.route}, Aggregate: ${metadata.aggregateType}`);
 *   const instance = new handlerClass();
 * }
 * ```
 */
export function getCommandHandlers(): Map<string, CommandHandlerEntry> {
  return COMMAND_HANDLERS;
}

/**
 * Get legacy command handlers (stateless mode)
 * For backward compatibility with existing CevesApp
 *
 * @returns Map of class name → constructor
 */
export function getLegacyCommandHandlers(): Map<string, Function> {
  return LEGACY_COMMAND_HANDLERS;
}

/**
 * Get handlers for specific aggregate type
 *
 * @param aggregateType - Aggregate type to filter by
 * @returns Array of handler entries for that aggregate
 *
 * @example
 * ```typescript
 * const bankHandlers = getHandlersByAggregateType('bank-account');
 * // Returns all handlers for bank-account aggregate
 * ```
 */
export function getHandlersByAggregateType(
  aggregateType: string
): CommandHandlerEntry[] {
  const handlers: CommandHandlerEntry[] = [];

  for (const [_key, entry] of COMMAND_HANDLERS) {
    if (entry.metadata.aggregateType === aggregateType) {
      handlers.push(entry);
    }
  }

  return handlers;
}

/**
 * Find handler by route and aggregate type
 *
 * @param route - Route pattern
 * @param aggregateType - Aggregate type
 * @returns Handler entry or undefined
 */
export function findHandler(
  route: string,
  aggregateType: string
): CommandHandlerEntry | undefined {
  const key = `${aggregateType}:${route}`;
  return COMMAND_HANDLERS.get(key);
}

/**
 * Find command handler by matching request path and method against registered routes
 *
 * This function is used by Durable Objects to find the appropriate handler
 * for an incoming request. It supports path parameter matching (e.g., :id).
 *
 * @param aggregateType - Aggregate type
 * @param requestPath - Actual request path (e.g., '/accounts/acc-123/debit')
 * @param requestMethod - HTTP method (e.g., 'POST')
 * @returns Handler entry or undefined if no match
 *
 * @example
 * ```typescript
 * // Handler registered with route: '/accounts/:id/debit'
 * const handler = findHandlerByPath('bank-account', '/accounts/acc-123/debit', 'POST');
 * // Returns the DebitAccountHandler
 * ```
 */
export function findHandlerByPath(
  aggregateType: string,
  requestPath: string,
  requestMethod: string = 'POST'
): CommandHandlerEntry | undefined {
  // Iterate through registered handlers for this aggregate type
  for (const entry of COMMAND_HANDLERS.values()) {
    if (entry.metadata.aggregateType !== aggregateType) {
      continue;
    }

    const handlerMethod = entry.metadata.method || 'POST';
    if (handlerMethod.toUpperCase() !== requestMethod.toUpperCase()) {
      continue;
    }

    // Check if request path matches route pattern
    if (matchPath(entry.metadata.route, requestPath)) {
      return entry;
    }
  }

  return undefined;
}

/**
 * Match a request path against a route pattern with parameter support
 *
 * Supports path parameters using :paramName syntax.
 *
 * @param routePattern - Route pattern (e.g., '/accounts/:id/debit')
 * @param requestPath - Actual request path (e.g., '/accounts/acc-123/debit')
 * @returns true if paths match
 *
 * @internal
 */
function matchPath(routePattern: string, requestPath: string): boolean {
  // Simple exact match first
  if (routePattern === requestPath) {
    return true;
  }

  // Split into segments
  const patternSegments = routePattern.split('/').filter(Boolean);
  const pathSegments = requestPath.split('/').filter(Boolean);

  // Must have same number of segments
  if (patternSegments.length !== pathSegments.length) {
    return false;
  }

  // Match each segment
  for (let i = 0; i < patternSegments.length; i++) {
    const patternSegment = patternSegments[i]!; // Length already validated
    const pathSegment = pathSegments[i];

    // Parameter segment (e.g., :id, :aggregateId)
    if (patternSegment.startsWith(':')) {
      continue; // Any value matches a parameter
    }

    // Literal segment must match exactly
    if (patternSegment !== pathSegment) {
      return false;
    }
  }

  return true;
}

/**
 * Clear all registered command handlers
 * FOR TESTING ONLY
 */
export function clearCommandHandlers(): void {
  COMMAND_HANDLERS.clear();
  LEGACY_COMMAND_HANDLERS.clear();
}
