/**
 * OpenAccountHandler - Create a new bank account
 *
 * Domain Rules:
 * - Account must not already exist (state must be null)
 * - Owner name must be provided
 * - Initial deposit must be non-negative
 */

import { CommandHandler, BusinessRuleViolationError } from 'ceves';
import { OpenAPIRoute } from 'chanfana';
import { z } from 'zod';
import type { OpenAccountCommand, AccountState } from '../types';

// Request/Response Schemas for Chanfana
const OpenAccountParams = z.object({
  id: z.string().describe('Account ID'),
});

const OpenAccountBody = z.object({
  owner: z.string().min(1).describe('Account owner name'),
  initialDeposit: z.number().min(0).describe('Initial deposit amount'),
});

const OpenAccountResponse = z.object({
  success: z.boolean(),
  aggregateId: z.string(),
  version: z.number(),
});

@CommandHandler({
  route: '/accounts/:id/open',
  aggregateType: 'account',
  method: 'POST',
  schema: {
    request: {
      params: OpenAccountParams,
      body: OpenAccountBody,
    },
    responses: {
      200: OpenAccountResponse,
      400: z.object({ error: z.string(), message: z.string() }),
    },
  },
  openapi: {
    summary: 'Open a new bank account',
    description: 'Creates a new bank account with an initial deposit',
    tags: ['Bank Account'],
  },
})
export class OpenAccountHandler extends OpenAPIRoute {
  /**
   * Execute the OpenAccount command
   *
   * @param command - Validated OpenAccount command with owner and initialDeposit
   * @param state - Current account state (must be null for new accounts)
   * @returns AccountOpened event
   * @throws Error if account already exists
   */
  async executeCommand(
    command: OpenAccountCommand,
    state: AccountState | null
  ): Promise<{ type: string; data: unknown }> {
    // Business rule: Cannot open an account that already exists
    if (state !== null) {
      throw new BusinessRuleViolationError('Account already exists');
    }

    // Return event to be persisted
    return {
      type: 'AccountOpened',
      data: {
        owner: command.owner,
        initialDeposit: command.initialDeposit,
      },
    };
  }
}
