/**
 * AccountOpenedHandler - Handle AccountOpened events
 *
 * Creates initial account state from null
 */

import { EventHandler, type IEventHandler } from 'ceves';
import type { AccountState, AccountOpenedEvent } from '../types';
import { AccountOpenedEventSchema } from '../types';

@EventHandler({
  eventType: 'AccountOpened',
  aggregateType: 'account'
})
export class AccountOpenedHandler
  implements IEventHandler<AccountState, AccountOpenedEvent>
{
  eventType = 'AccountOpened';
  schema = AccountOpenedEventSchema;

  /**
   * Apply AccountOpened event to create initial state
   *
   * @param state - Previous state (must be null for AccountOpened)
   * @param event - AccountOpened event with owner and initialDeposit
   * @returns New AccountState with initial balance
   */
  apply(state: AccountState | null, event: AccountOpenedEvent): AccountState {
    // AccountOpened is always the first event, state should be null
    if (state !== null) {
      throw new Error('AccountOpened event can only be applied to null state');
    }

    return {
      id: event.aggregateId,
      orgId: event.data.orgId,  // Tenant/organization that owns this account
      owner: event.data.owner,
      balance: event.data.initialDeposit,
      version: event.version,
      timestamp: event.timestamp,  // Updated from createdAt to match BaseState
    };
  }
}
